import{_ as t,o as i,c as o,ai as a,ao as s,ap as n,aq as r}from"./chunks/framework.DO_cB6UY.js";const m=JSON.parse('{"title":"VoIP Setup","description":"","frontmatter":{},"headers":[],"relativePath":"VoIP Setup.md","filePath":"VoIP Setup.md"}'),l={name:"VoIP Setup.md"};function d(c,e,h,p,u,v){return i(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="voip-setup" tabindex="-1">VoIP Setup <a class="header-anchor" href="#voip-setup" aria-label="Permalink to “VoIP Setup”">​</a></h1><p>At the time of writing the entire VoIP Code and Setup has been completely rewritten in order to improve on stability and scalability. Setting up VoIP requires a bit of initial work.</p><p>The following document is based on the setup of the official instance and works pretty flawless once setup.</p><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p></p><p>If you use linux and want to run DCTS on a proper server you could install and use Plesk on your server to have an easier time with managing sub domains and reverse proxy setups. Personally i&#39;d recommend it as i dont wanna manually deal with config files etc.</p></div><hr><h2 id="dns-setup" tabindex="-1">DNS Setup <a class="header-anchor" href="#dns-setup" aria-label="Permalink to “DNS Setup”">​</a></h2><p>Its recommended to create two subdomains for the VoIP system to make things easier. The subdomains are used for the reverse proxies and they should point to the server where you run DCTS and livekit.</p><table tabindex="0"><thead><tr><th>Type</th><th>Name</th><th>Content</th><th>Proxy needed?</th></tr></thead><tbody><tr><td>A</td><td>chat</td><td>your.ip.address</td><td>Yes</td></tr><tr><td>CNAME</td><td>lk</td><td>chat.domain.com</td><td>Yes</td></tr></tbody></table><div class="warning custom-block github-alert"><p class="custom-block-title">WARNING</p><p></p><p>Please note that you will need to have valid TLS certificates for your subdomains and access to the cert files as they will be needed later for the configuration of livekit.</p></div><hr><h2 id="livekit-reverse-proxy-setup" tabindex="-1">LiveKit Reverse Proxy Setup <a class="header-anchor" href="#livekit-reverse-proxy-setup" aria-label="Permalink to “LiveKit Reverse Proxy Setup”">​</a></h2><p>You can find the example proxy configs for livekit in [[network/Reverse Proxy Setup|Reverse Proxy Setup]]. Once you have done that you can check if the url works like below.</p><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p></p><p>You can verify if livekit works by entering your subdomain in a browser and check if you&#39;ll see <code>OK</code> like in the screenshot below, given you&#39;ve already installed livekit and its running.</p></div><p><img src="'+s+'" alt="image-20251108182904477"></p><hr><h2 id="livekit-service-config-setup" tabindex="-1">LiveKit Service Config Setup <a class="header-anchor" href="#livekit-service-config-setup" aria-label="Permalink to “LiveKit Service Config Setup”">​</a></h2><p>This step assumes you&#39;ve already installed livekit on your server with the install instructions found in the readme file. If thats the case, you should find a livekit config file inside the <code>/home/livekit</code> folder called <code>livekit.yaml</code>, like in the screenshot below.</p><p>Its important that you set <code>enabled</code> to <code>true</code>, and change the <code>domain</code> value to the domain you&#39;re using and linking the TLS certificate files. After you&#39;ve setup the config file you can exit your editor of choice and restart livekit using <code>service livekit restart</code>.</p><p><img src="'+n+'" alt=""></p><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p></p><p>Turn and TLS is required if you want others to be able to connect to VoIP. Its used for both talking and screensharing.</p><p>The sub-domain <code>livekit</code> shown in the screenshot would need to be replaced with <code>lk</code> as with the given DNS example above</p><p>The <code>key</code> shown at line 2 can be changed freely and needs to match with the <code>livekit</code> settings inside the <code>configs/config.json</code> file.</p></div><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p></p><p>You can try and find errors by viewing the livekit log using <code>sudo journalctl -u livekit -f</code>. Both the desktop and web client will show logs inside the Web Dev Console (CTRL + Shift + i).</p></div><hr><h2 id="livekit-dcts-config-setup" tabindex="-1">LiveKit DCTS Config Setup <a class="header-anchor" href="#livekit-dcts-config-setup" aria-label="Permalink to “LiveKit DCTS Config Setup”">​</a></h2><p>Inside the <code>config.json</code> file in found in the <code>configs/</code>, you will find a section for livekit. This is where you set it to enabled and enter the other relevant data found inside the <code>livekit.yaml</code> file from the previous step. Once everything is set VoIP and Screensharing should work flawlessly now.</p><p><img src="'+r+'" alt="image-20251108182459231"></p><div class="warning custom-block github-alert"><p class="custom-block-title">WARNING</p><p></p><p>Before editing <strong>anything</strong> inside the config file manually, makes sure to stop the server/livekit, as your changes may get lost.</p></div>',26)])])}const k=t(l,[["render",d]]);export{m as __pageData,k as default};
